mapper.select:
SELECT admin_id, admin_pw, adm_email_id, adm_email_addr, last_login_at
FROM   ADM_LOGIN_INFO
WHERE  admin_id = #{adminId}

mapper.update:
UPDATE ADM_LOGIN_INFO
SET    last_login_at = NOW()
WHERE  admin_id = #{adminId}

UPDATE BRD_POST_MST
   SET comment_cnt = (
           SELECT COUNT(*)
             FROM BRD_POST_COMMENT
            WHERE post_no = #{postNo}
              AND del_yn  = 'N'
       )
 WHERE post_no = #{postNo}

mapper.select:
SELECT approval_yn
  FROM BRD_POST_COMMENT
 WHERE comment_no = #{commentNo}

mapper.update:
UPDATE ADM_LOGIN_INFO
   SET admin_pw = #{adminPw}
 WHERE admin_id = #{adminId}

